        roots_set = sorted(roots)

        # Find all integer roots of x^4 + 5x^3 + 9x^2 - x - 14 = 0
        def f(x):
            return x**4 + 5*x**3 + 9*x**2 - x - 14

        # By rational root theorem, integer roots must divide 14
        # Possible integer roots: ±1, ±2, ±7, ±14
        actual_roots = []
        for x in range(-100, 101):
