def verify(answer):
    from sympy import isprime

    # Find all ways to write 100 as sum of a 1-digit prime and a 2-digit prime
    one_digit_primes = [p for p in range(2, 10) if isprime(p)]

    products = set()
    for p in one_digit_primes:
        q = 100 - p
        if 10 <= q <= 99 and isprime(q):
            products.add(p * q)

    # The problem implies there's a unique such decomposition (or unique product)
    # Check if the candidate answer matches any valid product
    try:
        ans = int(str(answer).strip())
        return ans in products and len(products) == 1
    except Exception:
        return False

