def verify(answer):
    try:
        ans = int(str(answer).strip())
        # Compute 10.3^3 exactly using fractions to avoid floating point issues
        from fractions import Fraction
        val = Fraction(103, 10) ** 3
        # Greatest integer less than val is floor(val) if val is not integer,
        # or val - 1 if val is integer
        if val.denominator == 1:
            result = int(val) - 1
        else:
            result = int(val) if val > 0 else int(val) - 1
            # Actually, floor for positive fractions
            result = val.numerator // val.denominator
            if val < 0 and val.numerator % val.denominator != 0:
                result -= 1
        # But we need greatest integer LESS than (strictly), not floor
        # floor(x) = greatest integer <= x
        # greatest integer < x: if x is integer, x-1; else floor(x)
        floor_val = val.numerator // val.denominator
        if val < 0 and val.numerator % val.denominator != 0:
            floor_val -= 1
        if val == floor_val:
            result = floor_val - 1
        else:
            result = floor_val
        return ans == result
    except Exception:
        return False

