def verify(answer):
    import math

    # Find all b such that distance from (1,2) to (4,b) is 5
    # (4-1)^2 + (b-2)^2 = 25
    # 9 + (b-2)^2 = 25
    # (b-2)^2 = 16
    # b-2 = ±4
    # b = 6 or b = -2

    correct_values = set()
    for b_times_10 in range(-1000, 1000):
        b = b_times_10 / 10.0
        dist_sq = (4 - 1)**2 + (b - 2)**2
        if abs(dist_sq - 25) < 1e-9:
            # Check if b is integer
            if abs(b - round(b)) < 1e-9:
                correct_values.add(int(round(b)))

    # Parse the answer - expect comma-separated values
    try:
        answer_str = str(answer).strip()
        parts = [p.strip() for p in answer_str.split(',')]
        answer_values = set()
        for p in parts:
            val = float(p)
            if abs(val - round(val)) < 1e-9:
                answer_values.add(int(round(val)))
            else:
                answer_values.add(val)
        return answer_values == correct_values
    except Exception:
        return False

