    from itertools import product as iproduct

    # We need to find integer roots r1, r2, r3 such that:
    # x^3 - 147x + c = (x - r1)(x - r2)(x - r3)
    # Expanding: x^3 - (r1+r2+r3)x^2 + (r1*r2 + r1*r3 + r2*r3)x - r1*r2*r3
    # So: r1 + r2 + r3 = 0 (coefficient of x^2 is 0)
    #     r1*r2 + r1*r3 + r2*r3 = -147
    #     c = -r1*r2*r3
    # |r1|, |r2|, |r3| are all primes

    # Each root is either p or -p for some prime p
    # r1 + r2 + r3 = 0
    # r1*r2 + r1*r3 + r2*r3 = -147

    # Note: sum of squares = (r1+r2+r3)^2 - 2(r1r2+r1r3+r2r3) = 0 - 2(-147) = 294
    # So |r1|^2 + |r2|^2 + |r3|^2 = 294

    # Find all primes p with p^2 <= 294, so p <= 17
    primes = [p for p in range(2, 18) if isprime(p)]

