def verify(answer):
    import itertools

    ROWS, COLS = 4, 6
    # Generate all possible L-triomino placements
    # L-triomino: 2x2 square missing one corner - 4 orientations
    pieces = []
    for r in range(ROWS - 1):
        for c in range(COLS - 1):
            # 4 cells of 2x2 block
            block = [(r, c), (r, c+1), (r+1, c), (r+1, c+1)]
            for i in range(4):
                piece = tuple(sorted(block[:i] + block[i+1:]))
                pieces.append(piece)

    # Remove duplicates
    pieces = list(set(pieces))

    # Backtracking to find all tilings
    grid = [[False]*COLS for _ in range(ROWS)]

    def find_first_empty():
        for r in range(ROWS):
            for c in range(COLS):
                if not grid[r][c]:
                    return (r, c)
        return None

    def get_pieces_covering(r, c):
        result = []
        for p in pieces:
            if (r, c) in p:
                if all(not grid[rr][cc] for rr, cc in p):
                    result.append(p)
        return result

    def neighbors(p1, p2):
        # Check if two triominoes share a positive amount of perimeter (edge)
        for r1, c1 in p1:
            for r2, c2 in p2:
                if abs(r1-r2) + abs(c1-c2) == 1:
                    return True
        return False

    def count_colorings(tiling):
        n = len(tiling)
        adj = [[] for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                if neighbors(tiling[i], tiling[j]):
                    adj[i].append(j)
                    adj[j].append(i)
        # Count proper 3-colorings
        count = 0
        colors = [0]*n
        def bt(idx):
            nonlocal count
            if idx == n:
                count += 1
                return
            for col in range(3):
                ok = True
                for nb in adj[idx]:
                    if nb < idx and colors[nb] == col:
                        ok = False
                        break
                if ok:
                    colors[idx] = col
                    bt(idx + 1)
        bt(0)
        return count

    all_tilings = []
    placement = []

    def solve():
        pos = find_first_empty()
        if pos is None:
            all_tilings.append(list(placement))
            return
        r, c = pos
        for p in get_pieces_covering(r, c):
            for rr, cc in p:
                grid[rr][cc] = True
            placement.append(p)
            solve()
            placement.pop()
            for rr, cc in p:
                grid[rr][cc] = False

    solve()

    total = 0
    for tiling in all_tilings:
        total += count_colorings(tiling)

    try:
        return int(str(answer).strip()) == total
    except:
        return False
